module asyn_fifo (
    input wclk, 
    input rclk, 
    input wrstn, 
    input rrstn, 
    input winc, 
    input rinc, 
    input [WIDTH-1:0] wdata,
    output wfull, 
    output rempty, 
    output [WIDTH-1:0] rdata
);

parameter DEPTH = 16;
parameter WIDTH = 8;

reg [($clog2(DEPTH))-1:0] waddr_bin;
reg [($clog2(DEPTH))-1:0] raddr_bin;

wire [($clog2(DEPTH))+1:0] wptr;
wire [($clog2(DEPTH))+1:0] rptr;

wire wfull_val;
wire rempty_val;

dual_port_RAM ram (
    .wclk(wclk),
    .wenc(winc & wrstn),
    .waddr(waddr_bin),
    .wdata(wdata),
    .rclk(rclk),
    .renc(rinc & rrstn),
    .raddr(raddr_bin),
    .rdata(rdata)
);

always @(posedge wclk or negedge wrstn) begin
    if (!wrstn) begin
        waddr_bin <= 0;
    end else if (winc) begin
        waddr_bin <= waddr_bin + 1;
    end
end

always @(posedge rclk or negedge rrstn) begin
    if (!rrstn) begin
        raddr_bin <= 0;
    end else if (rinc) begin
        raddr_bin <= raddr_bin + 1;
    end
end

assign wptr[0] = waddr_bin[0];
assign wptr[1] = waddr_bin[1] ^ wptr[0];
assign wptr[2] = waddr_bin[2] ^ wptr[1];
assign wptr[3] = waddr_bin[3] ^ wptr[2];
assign wptr[4] = waddr_bin[4] ^ wptr[3];
assign wptr[5] = waddr_bin[5] ^ wptr[4];
assign wptr[6] = waddr_bin[6] ^ wptr[5];
assign wptr[7] = waddr_bin[7] ^ wptr[6];

assign rptr[0] = raddr_bin[0];
assign rptr[1] = raddr_bin[1] ^ rptr[0];
assign rptr[2] = raddr_bin[2] ^ rptr[1];
assign rptr[3] = raddr_bin[3] ^ rptr[2];
assign rptr[4] = raddr_bin[4] ^ rptr[3];
assign rptr[5] = raddr_bin[5] ^ rptr[4];
assign rptr[6] = raddr_bin[6] ^ rptr[5];
assign rptr[7] = raddr_bin[7] ^ rptr[6];

assign wfull_val = (wptr == {~rptr[7], rptr[6:0]});
assign rempty_val = (wptr == rptr);

reg [($clog2(DEPTH))+1:0] wptr_buff;
always @(posedge wclk or negedge wrstn) begin
    if (!wrstn) begin
        wptr_buff <= 0;
    end else begin
        wptr_buff <= wptr;
    end
end

reg [($clog2(DEPTH))+1:0] rptr_buff;
always @(posedge rclk or negedge rrstn) begin
    if (!rrstn) begin
        rptr_buff <= 0;
    end else begin
        rptr_buff <= rptr;
    end
end

assign wfull = wfull_val;
assign rempty = rempty_val;

endmodule
